    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xF58E4E00B380E013ULL + 0x95B96D6E63610177ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xB07FAEB7B585D801ULL + 0x96B6A9E0E18EAE2DULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xC491CC6453826425ULL + 0xCC12E3B4304C6120ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xD118974EC344C821ULL + 0x8C0521A989C86DA1ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0xF0542796A48C57B5ULL + 0x834DE1401AD29547ULL);
