    std::uint64_t aNonceWordM = TwistMix64::DiffuseA(pNonce * 0x844CE263AC4638ABULL + 0xAD9A93E63F852EBCULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xB249EC006A996281ULL + 0xE64534628DE72945ULL);
