            aOrbiterF = (aWandererC + RotL64(aCross, 11U)) + 13099263173016322486U;
            aOrbiterD = (((aWandererH + RotL64(aScatter, 37U)) + RotL64(aCarry, 57U)) + 7041561081767500660U) + aOrbiterAssignSaltC[((aIndex + 3U)) & S_SALT1];
            aOrbiterJ = (aWandererG + RotL64(aPrevious, 19U)) + 6196422612687812971U;
