            aOrbiterD = RotL64((aOrbiterD * 16041243617369003291U), 53U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 2403828181385259549U;
            aOrbiterE = (aOrbiterE ^ aOrbiterB) ^ 17813580350434928194U;
            aOrbiterE = RotL64((aOrbiterE * 13666780980793857831U), 19U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterE) + 5623611126885414523U) + aOrbiterUpdateSaltF[((aIndex + 29U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterC) ^ 7293224381174846969U;
            aOrbiterI = RotL64((aOrbiterI * 7032561584670788117U), 43U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterC) + 10602620906929686163U;
            aOrbiterF = (aOrbiterF ^ aOrbiterA) ^ 18015916257203385982U;
            aOrbiterF = RotL64((aOrbiterF * 10684090189688871993U), 21U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterG) + 13592915735376305773U;
            aOrbiterA = (aOrbiterA ^ aOrbiterD) ^ 13995866908043417505U;
            aOrbiterA = RotL64((aOrbiterA * 3802175869395887331U), 3U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterD) + 8200465989447697618U) + aOrbiterUpdateSaltA[((aIndex + 4U)) & S_SALT1];
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterH) ^ 9866671660800629464U) ^ aNonceWordG;
