            aOrbiterH = RotL64((aOrbiterH * 11068705423012265209U), 41U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 13404720733342982167U;
            aOrbiterK = ((aOrbiterK ^ aOrbiterJ) ^ 13128574378042136042U) ^ aNonceWordF;
