            //
            aWandererC = aWandererC + ((RotL64(aScatter, 51U) + aOrbiterD) + RotL64(aOrbiterH, 47U));
            aWandererJ = aWandererJ ^ (((RotL64(aCross, 3U) + aOrbiterB) + RotL64(aOrbiterJ, 34U)) + aNonceWordA);
            aWandererI = aWandererI + (((RotL64(aPrevious, 28U) + RotL64(aOrbiterI, 11U)) + aOrbiterE) + aNonceWordB);
